INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('disabled-e0adf6cd-moex-00068', 'disabled-e0adf6cd', 'disabled-e0adf6cd-moex-114-3082b5f1', 'sub-disabled-e0adf6cd-05', NULL, 'single_choice', '甲市政府自行興建公立停車場，委託乙公司經營。由於乙未能對於該停車 場內手扶梯定期進行保養，因而造成人民跌落受傷，在此等情形下甲之責 任為何？', '["由於實際經營管理者為乙，故甲無國家賠償法之適用", "雖然該停車場為甲所興建，然該等事故並非設置有所欠缺所造成，故無 國家賠償法之適用", "雖然該停車場委託私人管理，然因該停車場仍供公共使用，故甲仍應依 法負國家賠償責任", "該事故雖沒有成立國家賠償責任之可能，但甲仍須對該受傷人民負民事 侵權行為損害賠償責任"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:14+00:00", "source_pdf_sha1": "03b0ee471a0c", "answer_pdf_sha1": "a7faea101c05", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "303", "s": "0302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "教育行政"}'::jsonb, NULL),
  ('disabled-e0adf6cd-moex-00069', 'disabled-e0adf6cd', 'disabled-e0adf6cd-moex-114-3082b5f1', 'sub-disabled-e0adf6cd-05', NULL, 'single_choice', '甲為A國人民，來我國騎自行車環島，行經道路路燈旁休息時，因路燈漏 電電擊休克致死，甲之父母請求我國國家賠償，下列敘述何者正確？', '["外國人並無國家賠償法之適用", "道路路燈屬自然公物內之設施，如經適當之警告或標示，而人民仍從事 具危險性活動，得減輕或免除國家賠償責任", "被害人甲死亡，其父母依國家賠償法適用民法第194條，得請求賠償慰 撫金", "須視我國與A國有無締結對等互惠之行政協議，以決定是否賠償"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:14+00:00", "source_pdf_sha1": "03b0ee471a0c", "answer_pdf_sha1": "a7faea101c05", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "303", "s": "0302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "教育行政"}'::jsonb, NULL),
  ('disabled-e0adf6cd-moex-00070', 'disabled-e0adf6cd', 'disabled-e0adf6cd-moex-113-856e6567', 'sub-disabled-e0adf6cd-02', NULL, 'essay', '試從哲學家思維、教育目的、教材內容、教學方法與教學評量模式此五個
層面，論述「哲學」與「教育」之密切關係，並從中外教育發展歷程，分
別列舉任一實例驗證之。（25 分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:14+00:00", "source_pdf_sha1": "55e64135588c", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "303", "s": "0801", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "教育哲學", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": "一", "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "教育行政"}'::jsonb, NULL),
  ('disabled-e0adf6cd-moex-00071', 'disabled-e0adf6cd', 'disabled-e0adf6cd-moex-113-856e6567', 'sub-disabled-e0adf6cd-02', NULL, 'essay', '近年來，國內校園師生間、學生間、親師間之衝突，屢聞不鮮；尤其，去
年（2023）年底發生令我國社會震驚的新北市國中生割頸案，足見「倫理
道德」與「法規」教育之迫切性；回顧古賢荀子以「明禮法」為主要教育
目標，尤其，其主張「禮」是「法」之基礎，試以合理性申論「禮」之意
涵，並進而論述合理性的「禮」對學生、老師、校長、教育行政公務員有
何重要性。（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:14+00:00", "source_pdf_sha1": "55e64135588c", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "303", "s": "0801", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "教育哲學", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": "二", "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "教育行政"}'::jsonb, NULL),
  ('disabled-e0adf6cd-moex-00072', 'disabled-e0adf6cd', 'disabled-e0adf6cd-moex-113-856e6567', 'sub-disabled-e0adf6cd-02', NULL, 'essay', '試依序分別論述下列哲學家思維之核心教育哲學意涵：（每小題5 分，共
25 分）
孔子對孟懿子問孝，子曰：「無違。」對孟武伯問孝，子曰：「父母唯
其疾之憂」。
荀子曾言：「故不積蹞步，無以致千里；……。鍥而舍之，朽木不折；
鍥而不舍，金石可鏤」。
老子曾謂：「合抱之木，生於毫末；九層之臺，起於累土；千里之行，
始於足下」。
德國的康德（ImmanuelKant,1724-1804）曾說：「沒有內涵的思想是空
的，沒有概念的直覺是盲的」。
瑞士的盧梭（J.J.Rousseau,1712-1778）主張：「來自於造物主手中的一
切都是善的，但一經人手（指成人或城人的手），就變壞了」。', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:14+00:00", "source_pdf_sha1": "55e64135588c", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "303", "s": "0801", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "教育哲學", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": "三", "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "教育行政"}'::jsonb, NULL),
  ('disabled-e0adf6cd-moex-00073', 'disabled-e0adf6cd', 'disabled-e0adf6cd-moex-113-856e6567', 'sub-disabled-e0adf6cd-02', NULL, 'essay', '如果人類的軀殼肉體是源自於自然物種的進化，那麼人類的心靈思考就是
其獨特符號文化交互統整的過程，足見「符號」與人類關係之密切；洞察
學校教育的歷程宛若是眾多符號交互作用的綜合展現，而「符號學」應用
於國內教育尚屬新興領域，亟需了解，試論述「符號學」之意涵，並列舉
說明四項「符號」的特性。（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:14+00:00", "source_pdf_sha1": "55e64135588c", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "303", "s": "0801", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "教育哲學", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": "四", "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "教育行政"}'::jsonb, NULL),
  ('disabled-e0adf6cd-moex-00074', 'disabled-e0adf6cd', 'disabled-e0adf6cd-moex-113-236aff17', 'sub-disabled-e0adf6cd-03', NULL, 'essay', '學生的情緒困擾已成為影響其心理健康的重要原因，故而學習情緒調節策
略已成為重要的教育課題。請問何謂「情緒調節」（emotionregulation）？
又有那些具體的策略可以幫助學生調節情緒？（25 分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:14+00:00", "source_pdf_sha1": "740c88426e2a", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "303", "s": "0802", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "教育心理學", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": "一", "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "教育行政"}'::jsonb, NULL),
  ('disabled-e0adf6cd-moex-00075', 'disabled-e0adf6cd', 'disabled-e0adf6cd-moex-113-236aff17', 'sub-disabled-e0adf6cd-03', NULL, 'essay', '艾瑞克森（Erikson）認為人的一生需經過八個不同的心理社會發展階段。
